exercises.solution_code:
#include <iostream>
#include <iomanip>

struct Thermometer {
    double celsius {};

    double getCelsius() const {
        return celsius;
    }

    double getFahrenheit() const {
        return celsius * 9.0 / 5.0 + 32.0;
    }
};

int main() {
    double temp {};
    std::cin >> temp;

    const Thermometer t { temp };

    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Celsius: " << t.getCelsius() << "\n";
    std::cout << "Fahrenheit: " << t.getFahrenheit() << "\n";

    return 0;
}

