exercises.solution_code:
#include <iostream>

struct Rectangle {
    int width {};
    int height {};

    int getWidth() const {
        return width;
    }

    int getHeight() const {
        return height;
    }

    int getArea() const {
        return width * height;
    }

    int getPerimeter() const {
        return 2 * (width + height);
    }
};

void printInfo(const Rectangle& r) {
    std::cout << "Width: "     << r.getWidth()     << "\n";
    std::cout << "Height: "    << r.getHeight()    << "\n";
    std::cout << "Area: "      << r.getArea()      << "\n";
    std::cout << "Perimeter: " << r.getPerimeter() << "\n";
}

int main() {
    int w {}, h {};
    std::cin >> w >> h;

    const Rectangle rect { w, h };
    printInfo(rect);

    return 0;
}
